class StockPrice {
    private TreeMap<Integer, Integer> prices;
    private int latestTimestamp;
    private int latestPrice;
    private int maxPrice;
    private int minPrice;

    public StockPrice() {
        prices = new TreeMap<>();
    }

    public void update(int timestamp, int price) {
        if (prices.containsKey(timestamp)) {
            int oldPrice = prices.get(timestamp);
            maxPrice = Math.max(maxPrice, Math.max(price, oldPrice));
            minPrice = Math.min(minPrice, Math.min(price, oldPrice));
        } else {
            maxPrice = Math.max(maxPrice, price);
            minPrice = Math.min(minPrice, price == 0 ? Integer.MAX_VALUE : price);
        }
        prices.put(timestamp, price);
        if (timestamp > latestTimestamp) {
            latestTimestamp = timestamp;
            latestPrice = price;
        }
    }

    public int current() {
        return latestPrice;
    }

    public int maximum() {
        return maxPrice;
    }

    public int minimum() {
        return minPrice;
    }
}
